import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

export default function StudentDashboard() {
  const { user } = useAuth();
  const [memberships, setMemberships] = useState([]);
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [mRes, eRes] = await Promise.all([
          api.get('/memberships/my'),
          api.get('/events?status=published&limit=6'),
        ]);
        setMemberships(mRes.data.data || []);
        setEvents(eRes.data.data || []);
      } catch { toast.error('Failed to load data'); }
      finally { setLoading(false); }
    };
    fetchData();
  }, []);

  const approved = memberships.filter(m => m.status === 'approved');
  const pending = memberships.filter(m => m.status === 'pending');

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* Hero Section with Gradient Background */}
        <div style={{
          background: 'linear-gradient(135deg, rgba(15, 25, 35, 0.8) 0%, rgba(10, 18, 26, 0.9) 100%)',
          borderRadius: 'var(--border-radius-lg)',
          padding: '32px 28px',
          marginBottom: '32px',
          border: '1px solid rgba(0, 255, 255, 0.15)',
          position: 'relative',
          overflow: 'hidden',
        }}>
          <div style={{
            position: 'absolute',
            top: -50,
            right: -50,
            width: 200,
            height: 200,
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(0, 255, 255, 0.1) 0%, transparent 70%)',
            pointerEvents: 'none',
          }} />
          <div className="flex-between" style={{ position: 'relative', zIndex: 1 }}>
            <div>
              <h1 style={{
                fontFamily: 'var(--font-display)',
                fontSize: '2rem',
                marginBottom: '8px',
                letterSpacing: '-0.02em',
              }}>
                Welcome back,{' '}
                <span style={{
                  background: 'linear-gradient(135deg, #fff 0%, var(--cyan-accent) 100%)',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  backgroundClip: 'text',
                }}>
                  {user?.name?.split(' ')[0]}
                </span>
              </h1>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap' }}>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  background: 'rgba(0, 255, 255, 0.1)',
                  padding: '4px 12px',
                  borderRadius: '20px',
                  fontFamily: 'var(--font-mono)',
                  fontSize: '0.75rem',
                  color: 'var(--cyan-accent)',
                }}>
                  <span>🆔</span>
                  <span>{user?.itNumber}</span>
                </div>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  fontSize: '0.85rem',
                  color: 'var(--text-secondary)',
                }}>
                  <span>📧</span>
                  <span>{user?.email}</span>
                </div>
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <Link to="/clubs" className="btn btn-primary" style={{
                boxShadow: '0 4px 12px rgba(0, 255, 255, 0.2)',
                transition: 'transform 0.2s, box-shadow 0.2s',
              }}>✨ Explore Clubs</Link>
              <Link to="/student/profile" className="btn btn-outline">👤 My Profile</Link>
            </div>
          </div>
        </div>

        {/* Enhanced Stats Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '20px',
          marginBottom: '40px',
        }}>
          {[
            { label: 'Active Communities', value: approved.length, icon: '🏛️', color: 'var(--purple-light)', desc: 'You\'re a member of' },
            { label: 'Pending Requests', value: pending.length, icon: '⏳', color: 'var(--warning)', desc: 'Awaiting approval' },
            { label: 'Upcoming Events', value: events.length, icon: '📅', color: 'var(--cyan-accent)', desc: 'Happening soon' },
            { label: 'Member Since', value: new Date(user?.createdAt || Date.now()).getFullYear(), icon: '🎓', color: 'var(--success)', desc: 'Active member' },
          ].map((s, i) => (
            <div key={i} style={{
              background: 'rgba(10, 18, 26, 0.6)',
              backdropFilter: 'blur(10px)',
              borderRadius: '20px',
              padding: '20px 16px',
              border: '1px solid rgba(0, 255, 255, 0.1)',
              transition: 'all 0.3s ease',
              cursor: 'pointer',
            }} onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.borderColor = s.color;
            }} onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.1)';
            }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
                <span style={{ fontSize: '2rem' }}>{s.icon}</span>
                <span style={{ fontSize: '1.8rem', fontWeight: 700, color: s.color }}>{s.value}</span>
              </div>
              <div style={{ fontWeight: 600, fontSize: '0.9rem', marginBottom: '4px' }}>{s.label}</div>
              <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>{s.desc}</div>
            </div>
          ))}
        </div>

        {/* Two Column Layout with Enhanced Cards */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px' }}>
          {/* My Communities Section */}
          <div>
            <div className="flex-between" style={{ marginBottom: '20px' }}>
              <div>
                <h3 style={{
                  fontFamily: 'var(--font-display)',
                  fontSize: '1.3rem',
                  marginBottom: '4px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                }}>
                  <span>🏛️</span>
                  <span>My Communities</span>
                </h3>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                  {approved.length} active · {pending.length} pending
                </p>
              </div>
              <Link to="/clubs" style={{
                fontSize: '0.75rem',
                color: 'var(--cyan-accent)',
                textDecoration: 'none',
                padding: '6px 12px',
                borderRadius: '20px',
                background: 'rgba(0, 255, 255, 0.1)',
                transition: 'all 0.2s',
              }}>Browse More →</Link>
            </div>

            {memberships.length === 0 ? (
              <div className="card" style={{
                textAlign: 'center',
                padding: '48px 24px',
                background: 'linear-gradient(135deg, rgba(15, 25, 35, 0.5) 0%, rgba(10, 18, 26, 0.7) 100%)',
              }}>
                <div className="empty-state-icon" style={{ fontSize: '3rem', marginBottom: '16px' }}>🏛️</div>
                <div className="empty-state-text" style={{ marginBottom: '16px' }}>You haven't joined any communities yet</div>
                <Link to="/clubs" className="btn btn-primary btn-sm">Discover Communities</Link>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {memberships.map(m => (
                  <div key={m._id} style={{
                    background: 'rgba(10, 18, 26, 0.5)',
                    borderRadius: '16px',
                    padding: '16px 20px',
                    border: '1px solid rgba(0, 255, 255, 0.08)',
                    transition: 'all 0.2s ease',
                    cursor: 'pointer',
                  }} onMouseEnter={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.3)';
                    e.currentTarget.style.background = 'rgba(15, 25, 35, 0.7)';
                  }} onMouseLeave={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.08)';
                    e.currentTarget.style.background = 'rgba(10, 18, 26, 0.5)';
                  }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
                      <div style={{
                        width: '48px',
                        height: '48px',
                        borderRadius: '12px',
                        background: `linear-gradient(135deg, ${m.community?.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)'}20, transparent)`,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1.5rem',
                        fontWeight: 600,
                        color: m.community?.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)',
                        border: `1px solid ${m.community?.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)'}30`,
                      }}>
                        {m.community?.name?.charAt(0).toUpperCase()}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.95rem', marginBottom: '6px' }}>{m.community?.name}</div>
                        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                          <span className={`badge badge-${m.community?.category?.toLowerCase()}`} style={{ fontSize: '0.7rem' }}>{m.community?.category}</span>
                          <span style={{
                            fontSize: '0.7rem',
                            padding: '2px 8px',
                            borderRadius: '12px',
                            background: m.status === 'approved' ? 'rgba(0, 255, 0, 0.1)' : 'rgba(255, 193, 7, 0.1)',
                            color: m.status === 'approved' ? 'var(--success)' : 'var(--warning)',
                          }}>
                            {m.status === 'approved' ? '✓ Active' : '⏳ Pending'}
                          </span>
                        </div>
                      </div>
                    </div>
                    {m.status === 'pending' && (
                      <div style={{
                        marginTop: '12px',
                        paddingTop: '12px',
                        borderTop: '1px solid rgba(255, 255, 255, 0.05)',
                        fontSize: '0.7rem',
                        color: 'var(--text-muted)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '6px',
                      }}>
                        <span>⏳</span> Waiting for Community Admin approval
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Upcoming Events Section */}
          <div>
            <div className="flex-between" style={{ marginBottom: '20px' }}>
              <div>
                <h3 style={{
                  fontFamily: 'var(--font-display)',
                  fontSize: '1.3rem',
                  marginBottom: '4px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                }}>
                  <span>📅</span>
                  <span>Upcoming Events</span>
                </h3>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                  Don't miss out on these opportunities
                </p>
              </div>
              <Link to="/events" style={{
                fontSize: '0.75rem',
                color: 'var(--cyan-accent)',
                textDecoration: 'none',
                padding: '6px 12px',
                borderRadius: '20px',
                background: 'rgba(0, 255, 255, 0.1)',
                transition: 'all 0.2s',
              }}>View All →</Link>
            </div>

            {events.length === 0 ? (
              <div className="card" style={{
                textAlign: 'center',
                padding: '48px 24px',
                background: 'linear-gradient(135deg, rgba(15, 25, 35, 0.5) 0%, rgba(10, 18, 26, 0.7) 100%)',
              }}>
                <div className="empty-state-icon" style={{ fontSize: '3rem', marginBottom: '16px' }}>📅</div>
                <div className="empty-state-text">No events available at the moment</div>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '8px' }}>Check back later for updates</p>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {events.slice(0, 5).map(ev => (
                  <Link key={ev._id} to={`/events/${ev._id}`} style={{ textDecoration: 'none' }}>
                    <div style={{
                      background: 'rgba(10, 18, 26, 0.5)',
                      borderRadius: '16px',
                      padding: '16px 20px',
                      border: '1px solid rgba(0, 255, 255, 0.08)',
                      transition: 'all 0.2s ease',
                      cursor: 'pointer',
                    }} onMouseEnter={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.3)';
                      e.currentTarget.style.transform = 'translateX(4px)';
                      e.currentTarget.style.background = 'rgba(15, 25, 35, 0.7)';
                    }} onMouseLeave={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.08)';
                      e.currentTarget.style.transform = 'translateX(0)';
                      e.currentTarget.style.background = 'rgba(10, 18, 26, 0.5)';
                    }}>
                      <div className="flex-between" style={{ marginBottom: '8px' }}>
                        <div style={{ fontWeight: 600, fontSize: '0.95rem', color: 'white' }}>{ev.title}</div>
                        <span className={`badge badge-${ev.category?.toLowerCase()}`} style={{ fontSize: '0.7rem' }}>{ev.category}</span>
                      </div>
                      <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap', marginTop: '10px' }}>
                        <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                          <span>📅</span> {new Date(ev.startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                        </div>
                        <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                          <span>🏛️</span> {ev.community?.name}
                        </div>
                        {ev.location && (
                          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                            <span>📍</span> {ev.location}
                          </div>
                        )}
                      </div>
                    </div>
                  </Link>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Quick Actions Section */}
        <div style={{
          marginTop: '48px',
          padding: '28px 24px',
          borderRadius: '20px',
          background: 'linear-gradient(135deg, rgba(0, 255, 255, 0.03) 0%, rgba(0, 255, 255, 0.01) 100%)',
          border: '1px solid rgba(0, 255, 255, 0.1)',
        }}>
          <h4 style={{
            fontFamily: 'var(--font-display)',
            fontSize: '1rem',
            marginBottom: '20px',
            color: 'var(--text-secondary)',
            textTransform: 'uppercase',
            letterSpacing: '1px',
          }}>Quick Actions</h4>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px' }}>
            {[
              { icon: '🏛️', label: 'Find Clubs', link: '/clubs', color: 'var(--cyan-accent)' },
              { icon: '📅', label: 'Browse Events', link: '/events', color: 'var(--purple-light)' },
              { icon: '👥', label: 'My Network', link: '/student/network', color: 'var(--success)' },
              { icon: '⚙️', label: 'Settings', link: '/student/settings', color: 'var(--warning)' },
            ].map((action, idx) => (
              <Link key={idx} to={action.link} style={{ textDecoration: 'none' }}>
                <div style={{
                  padding: '12px',
                  borderRadius: '12px',
                  textAlign: 'center',
                  background: 'rgba(10, 18, 26, 0.4)',
                  transition: 'all 0.2s',
                  cursor: 'pointer',
                }} onMouseEnter={(e) => {
                  e.currentTarget.style.background = `rgba(0, 255, 255, 0.05)`;
                  e.currentTarget.style.transform = 'translateY(-2px)';
                }} onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'rgba(10, 18, 26, 0.4)';
                  e.currentTarget.style.transform = 'translateY(0)';
                }}>
                  <div style={{ fontSize: '1.5rem', marginBottom: '6px' }}>{action.icon}</div>
                  <div style={{ fontSize: '0.75rem', fontWeight: 500, color: 'var(--text-primary)' }}>{action.label}</div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
